import React, { useState, useEffect } from 'react';
import formatTime from '../utils/formatTime';

function Timer() {
  const [time, setTime] = useState(0);
  const [isRunning, setIsRunning] = useState(false);
  const [isPaused, setIsPaused] = useState(false);

  useEffect(() => {
    let interval;
    if (isRunning && !isPaused) {
      interval = setInterval(() => {
        setTime((prevTime) => prevTime + 1);
      }, 1000);
    } else {
      clearInterval(interval);
    }
    return () => clearInterval(interval);
  }, [isRunning, isPaused]);

  const handleStart = () => {
    setIsRunning(true);
    setIsPaused(false);
  };

  const handlePause = () => {
    setIsPaused(true);
  };

  const handleResume = () => {
    setIsPaused(false);
  };

  const handleStop = () => {
    setIsRunning(false);
    setIsPaused(false);
    playSound();
  };

  const handleReset = () => {
    setIsRunning(false);
    setIsPaused(false);
    setTime(0);
  };

  const playSound = () => {
    const audio = new Audio('/notification.mp3');
    audio.play();
  };

  const progress = (time % 60) / 60 * 100;

  return (
    <div className="text-center">
      <div className="relative w-40 h-40 mx-auto">
        <svg className="absolute top-0 left-0 w-full h-full">
          <circle
            cx="50%"
            cy="50%"
            r="45%"
            stroke="currentColor"
            strokeWidth="4"
            fill="none"
            className="text-gray-300"
          />
          <circle
            cx="50%"
            cy="50%"
            r="45%"
            stroke="currentColor"
            strokeWidth="4"
            fill="none"
            className="text-blue-500"
            strokeDasharray="283"
            strokeDashoffset={`${283 - (progress / 100) * 283}`}
            style={{ transition: 'stroke-dashoffset 0.5s linear' }}
          />
        </svg>
        <h1 className="absolute inset-0 flex items-center justify-center text-4xl font-bold">
          {formatTime(time)}
        </h1>
      </div>
      <div className="space-x-4 mt-4">
        {!isRunning && !isPaused && (
          <button className="px-4 py-2 bg-green-500 text-white rounded" onClick={handleStart}>Start</button>
        )}
        {isRunning && !isPaused && (
          <button className="px-4 py-2 bg-yellow-500 text-white rounded" onClick={handlePause}>Pause</button>
        )}
        {isRunning && isPaused && (
          <button className="px-4 py-2 bg-blue-500 text-white rounded" onClick={handleResume}>Resume</button>
        )}
        <button className="px-4 py-2 bg-red-500 text-white rounded" onClick={handleStop}>Stop</button>
        <button className="px-4 py-2 bg-gray-500 text-white rounded" onClick={handleReset}>Reset</button>
      </div>
    </div>
  );
}

export default Timer;
